    private final ConcurrentHashMap<String, OrderVO> idempotencyMap = new ConcurrentHashMap<>();

    public OrderVO createChargeOrder(OrderRequest request) {
        String requestId = request.getRequestId();

        // 1. 幂等判断：检查请求 ID 是否已处理
        if (idempotencyMap.containsKey(requestId)) {
            return idempotencyMap.get(requestId);
        }

        // 2. 执行核心业务逻辑
        OrderVO order = executeOrderCreation(request);

        // 3. 记录处理结果
        idempotencyMap.put(requestId, order);

        return order;
    }

    private OrderVO executeOrderCreation(OrderRequest request) {
        OrderVO vo = new OrderVO();
        vo.setOrderId("ORD_" + System.currentTimeMillis());
        vo.setStatus("CREATED");
        return vo;
    }
}
